// Placeholder: In production, this pulls from Plaid/Lean/Xero/QuickBooks API
// For now, simulate with sample restaurant transaction data for Saffron Kitchen
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const formatDate = (d) => d.toISOString().split('T')[0];

const sampleTransactions = [
  { date: formatDate(new Date(now.getTime() - 6 * 86400000)), description: 'Daily sales — dine-in', amount: 12500, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 6 * 86400000)), description: 'Daily sales — delivery (Talabat/Deliveroo)', amount: 4200, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 5 * 86400000)), description: 'Daily sales — dine-in', amount: 15800, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 5 * 86400000)), description: 'Supplier — fresh produce (Al Aweer Market)', amount: -3200, type: 'debit', category: '' },
  { date: formatDate(new Date(now.getTime() - 5 * 86400000)), description: 'Supplier — meat & poultry', amount: -5600, type: 'debit', category: '' },
  { date: formatDate(new Date(now.getTime() - 4 * 86400000)), description: 'Daily sales — dine-in', amount: 11200, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 4 * 86400000)), description: 'Daily sales — delivery', amount: 3800, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 4 * 86400000)), description: 'DEWA utilities', amount: -2800, type: 'debit', category: '' },
  { date: formatDate(new Date(now.getTime() - 3 * 86400000)), description: 'Daily sales — dine-in', amount: 18500, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 3 * 86400000)), description: 'Staff salary — kitchen team', amount: -14000, type: 'debit', category: '' },
  { date: formatDate(new Date(now.getTime() - 3 * 86400000)), description: 'Staff salary — service team', amount: -9500, type: 'debit', category: '' },
  { date: formatDate(new Date(now.getTime() - 2 * 86400000)), description: 'Daily sales — dine-in + catering', amount: 22000, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 2 * 86400000)), description: 'Supplier — spices & dry goods', amount: -1800, type: 'debit', category: '' },
  { date: formatDate(new Date(now.getTime() - 1 * 86400000)), description: 'Daily sales — dine-in', amount: 16300, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 1 * 86400000)), description: 'Daily sales — delivery', amount: 5100, type: 'credit', category: '' },
  { date: formatDate(new Date(now.getTime() - 1 * 86400000)), description: 'Rent — monthly installment', amount: -18000, type: 'debit', category: '' },
  { date: formatDate(now), description: 'POS software subscription', amount: -450, type: 'debit', category: '' },
  { date: formatDate(now), description: 'Marketing — Instagram ad campaign', amount: -1500, type: 'debit', category: '' },
  { date: formatDate(now), description: 'Bank transfer fees', amount: -120, type: 'debit', category: '' }
];

return [{
  json: {
    transactions: sampleTransactions,
    period: 'weekly',
    weekOf: formatDate(weekAgo),
    weekEnd: formatDate(now),
    transactionCount: sampleTransactions.length
  }
}];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '[]';

let categorized;
try {
  // Extract JSON array from response (handle markdown code blocks)
  const jsonMatch = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  categorized = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch (e) {
  // Fallback: use original transactions with empty categories
  categorized = $('Fetch Transactions').first().json.transactions;
}

// Calculate KPIs
const totalRevenue = categorized.filter(t => t.amount > 0).reduce((s, t) => s + t.amount, 0);
const totalExpenses = Math.abs(categorized.filter(t => t.amount < 0).reduce((s, t) => s + t.amount, 0));
const netCashFlow = totalRevenue - totalExpenses;

// Group expenses by category
const expensesByCategory = {};
for (const t of categorized.filter(t => t.amount < 0)) {
  const cat = t.category || 'Other';
  expensesByCategory[cat] = (expensesByCategory[cat] || 0) + Math.abs(t.amount);
}

return [{
  json: {
    categorizedTransactions: categorized,
    kpis: {
      totalRevenue,
      totalExpenses,
      netCashFlow,
      profitMargin: totalRevenue > 0 ? ((netCashFlow / totalRevenue) * 100).toFixed(1) + '%' : '0%',
      transactionCount: categorized.length
    },
    expensesByCategory,
    weekOf: $('Fetch Transactions').first().json.weekOf,
    weekEnd: $('Fetch Transactions').first().json.weekEnd
  }
}];

const response = $input.first().json;
const report = response.choices?.[0]?.message?.content || 'Report generation failed. Raw KPIs: ' + JSON.stringify($('Calculate KPIs').first().json.kpis);
const kpis = $('Calculate KPIs').first().json.kpis;
const weekOf = $('Calculate KPIs').first().json.weekOf;

return [{
  json: {
    report: report,
    kpis: kpis,
    weekOf: weekOf
  }
}];
